#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="D:\git\jiujing\node_modules\.pnpm\electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d\node_modules\electron-builder\node_modules;D:\git\jiujing\node_modules\.pnpm\electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d\node_modules;D:\git\jiujing\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/d/git/jiujing/node_modules/.pnpm/electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d/node_modules/electron-builder/node_modules:/mnt/d/git/jiujing/node_modules/.pnpm/electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d/node_modules:/mnt/d/git/jiujing/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../.pnpm/electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d/node_modules/electron-builder/cli.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../.pnpm/electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d/node_modules/electron-builder/cli.js" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../.pnpm/electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d/node_modules/electron-builder/cli.js" $args
  } else {
    & "node$exe"  "$basedir/../.pnpm/electron-builder@26.8.1_ele_65d556870c52a7e0ac4da9b01c567e7d/node_modules/electron-builder/cli.js" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
